from prometheus_client import Counter, Histogram, generate_latest
import time

# SLI metrics
request_total = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

request_duration = Histogram(
    'http_request_duration_seconds',
    'Request duration in seconds',
    ['method', 'endpoint'],
    buckets=[0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0]
)

# Business-level SLI: tracks actual user-facing failures
business_errors = Counter(
    'business_operation_errors_total',
    'Business logic failures (user-visible)',
    ['operation', 'reason']
)

@app.before_request
def start_timer():
    g.start_time = time.time()

@app.after_request
def record_metrics(response):
    duration = time.time() - g.start_time
    endpoint = request.endpoint or 'unknown'
    request_total.labels(
        method=request.method,
        endpoint=endpoint,
        status=response.status_code
    ).inc()
    request_duration.labels(
        method=request.method,
        endpoint=endpoint
    ).observe(duration)
    return response

@app.route('/api/checkout', methods=['POST'])
def checkout():
    try:
        result = process_payment(request.json)
        if not result.success:
            # This is a 200 OK but a business failure
            business_errors.labels(
                operation='checkout',
                reason=result.error_code
            ).inc()
        return jsonify(result.to_dict())
    except Exception as e:
        business_errors.labels(
            operation='checkout',
            reason='unhandled_exception'
        ).inc()
        raise

#!/usr/bin/env python3
"""Weekly SLO report generator - run via cron every Monday 9am."""
import requests
import json

PROMETHEUS = "http://prometheus:9090"
SLACK_WEBHOOK = "https://hooks.slack.com/services/T.../B.../xxx"

SLOS = [
    {"name": "Payment API", "job": "payment-api", "target": 0.999},
    {"name": "Search API", "job": "search-api", "target": 0.995},
]

def query_prometheus(query):
    r = requests.get(f"{PROMETHEUS}/api/v1/query", params={"query": query})
    return float(r.json()["data"]["result"][0]["value"][1])

def get_slo_status(job, target):
    availability = query_prometheus(
        f'sum(rate(http_requests_total{{job="{job}",status!~"5.."}}[30d]))'
        f' / sum(rate(http_requests_total{{job="{job}"}}[30d]))'
    )
    budget_consumed = (1 - availability) / (1 - target)
    return availability, budget_consumed

blocks = [{"type": "header", "text": {"type": "plain_text", "text": "Weekly SLO Report"}}]

for slo in SLOS:
    avail, consumed = get_slo_status(slo["job"], slo["target"])
    budget_pct = (1 - consumed) * 100
    emoji = ":white_check_mark:" if budget_pct > 30 else ":warning:" if budget_pct > 10 else ":fire:"
    blocks.append({
        "type": "section",
        "text": {
            "type": "mrkdwn",
            "text": f"{emoji} *{slo['name']}*\n"
                   f"Availability: {avail:.4%} (target: {slo['target']:.2%})\n"
                   f"Error budget remaining: {budget_pct:.1f}%"
        }
    })

requests.post(SLACK_WEBHOOK, json={"blocks": blocks})
